import random

def gamblers_ruin(player1_pennies, player2_pennies, iterations=10000):
    player1_wins = 0
    player2_wins = 0
    for _ in range(iterations):
        p1, p2 = player1_pennies, player2_pennies
        while p1 > 0 and p2 > 0:
            if random.random() < 0.5:
                p1 += 1
                p2 -= 1
            else:
                p1 -= 1
                p2 += 1
        if p1 == 0:
            player2_wins += 1
        else:
            player1_wins += 1
    print(f"Player 1 wins: {player1_wins/iterations:.2%}")
    print(f"Player 2 wins: {player2_wins/iterations:.2%}")

# Example: Player 1 starts with 5 pennies, Player 2 with 5 pennies
gamblers_ruin(5, 5)
